func solve(nums []int64) int64 {
    n := len(nums)
    if n == 0 {
        return 0
    }
    absNums := make([]int64, n)
    for i, v := range nums {
        if v < 0 {
            absNums[i] = -v
        } else {
            absNums[i] = v
        }
    }

